import React from 'react';
import styles from './HackathonCard.module.css';
import ParticipantsList from './ParticipantsList';

export default function HackathonCard({ hackathon }){
  return (
    <article className={styles.card}>
      <div className={styles.header}>
        <h3>{hackathon.title}</h3>
        <span className={styles.category}>{hackathon.category}</span>
      </div>
      <div className={styles.meta}>Дата: {hackathon.date}</div>
      <p className={styles.description}>{hackathon.description}</p>
      <ParticipantsList participants={hackathon.participants} />
    </article>
  );
}
